import sys

css_stylesheet = sys.stdin.readlines()

# Correct pseudo-class selector ordering
corrected_stylesheet = []
for line in css_stylesheet:
    if 'element:' in line and ':hover' in line:
        corrected_stylesheet.append(line.replace(':hover', ':focus'))
    elif 'element:' in line and ':focus' in line:
        corrected_stylesheet.append(line)
    else:
        corrected_stylesheet.append(line)

# Print corrected stylesheet
print('\n'.join(corrected_stylesheet))
